using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Data.Entity;
using System.Linq;
using System.Text.RegularExpressions;
using System.Web;
using System.Web.Mvc;

namespace ProductReviewsMvc.Controllers
{
    public class ReviewsController : Controller
    {
        private readonly ApplicationDbContext _db = new ApplicationDbContext();

        [HttpGet]
        public ActionResult Product(int productId)
        {
            var product = _db.Products
                .Include(p => p.Reviews)
                .FirstOrDefault(p => p.Id == productId);

            if (product == null)
            {
                return HttpNotFound();
            }

            var model = new ProductReviewsViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedAtUtc)
                    .Select(r => new ReviewDisplayViewModel
                    {
                        UserName = r.UserName,
                        Title = r.Title,
                        Rating = r.Rating,
                        CreatedAtUtc = r.CreatedAtUtc,
                        FormattedContent = BasicReviewFormatter.ToSafeHtml(r.Content)
                    })
                    .ToList(),
                NewReview = new CreateReviewViewModel
                {
                    ProductId = product.Id
                }
            };

            return View("Product", model);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult Create(CreateReviewViewModel model)
        {
            if (!ModelState.IsValid)
            {
                return RedirectToAction("Product", new { productId = model.ProductId });
            }

            var productExists = _db.Products.Any(p => p.Id == model.ProductId);
            if (!productExists)
            {
                return HttpNotFound();
            }

            var review = new Review
            {
                ProductId = model.ProductId,
                UserName = string.IsNullOrWhiteSpace(model.UserName) ? "Anonymous" : model.UserName.Trim(),
                Title = model.Title?.Trim(),
                Content = model.Content ?? string.Empty,
                Rating = model.Rating,
                CreatedAtUtc = DateTime.UtcNow
            };

            _db.Reviews.Add(review);
            _db.SaveChanges();

            return RedirectToAction("Product", new { productId = model.ProductId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }

            base.Dispose(disposing);
        }
    }

    public static class BasicReviewFormatter
    {
        public static IHtmlString ToSafeHtml(string input)
        {
            var encoded = HttpUtility.HtmlEncode(input ?? string.Empty);
            encoded = Regex.Replace(encoded, @"\*\*(.+?)\*\*", "<strong>$1</strong>", RegexOptions.Singleline);
            encoded = Regex.Replace(encoded, @"\*(.+?)\*", "<em>$1</em>", RegexOptions.Singleline);
            encoded = encoded.Replace("\r\n", "\n").Replace("\n", "<br />");
            return new HtmlString(encoded);
        }
    }

