/* Views/Reviews/Product.cshtml */
@model ProductReviewsMvc.Controllers.ProductReviewsViewModel
@{
    ViewBag.Title = Model.ProductName + " Reviews";
}

<h2>@Model.ProductName Reviews</h2>

@if (Model.Reviews != null && Model.Reviews.Any())
{
    <div class="reviews-list">
        @foreach (var review in Model.Reviews)
        {
            <article class="review-item">
                <h3>@review.Title</h3>
                <div>
                    <strong>@review.UserName</strong>
                    <span> - @review.CreatedAtUtc.ToLocalTime().ToString("g")</span>
                    <span> - Rating: @review.Rating/5</span>
                </div>
                <div class="review-content">
                    @review.FormattedContent
                </div>
                <hr />
            </article>
        }
    </div>
}
else
{
    <p>No reviews yet.</p>
}

<h3>Write a Review</h3>

@using (Html.BeginForm("Create", "Reviews", FormMethod.Post))
{
    @Html.AntiForgeryToken()
    @Html.HiddenFor(m => m.NewReview.ProductId)

    <div>
        @Html.LabelFor(m => m.NewReview.UserName)
        @Html.TextBoxFor(m => m.NewReview.UserName)
    </div>

    <div>
        @Html.LabelFor(m => m.NewReview.Title)
        @Html.TextBoxFor(m => m.NewReview.Title)
    </div>

    <div>
        @Html.LabelFor(m => m.NewReview.Rating)
        @Html.TextBoxFor(m => m.NewReview.Rating, new { type = "number", min = "1", max = "5" })
    </div>

    <div>
        @Html.LabelFor(m => m.NewReview.Content)
        @Html.TextAreaFor(m => m.NewReview.Content, 8, 60, null)
        <p>Formatting supported: **bold**, *italic*</p>
    </div>

    <button type="submit">Submit Review</button>
}